class StaticSignClassifier {
public:
    static std::string predict(const std::vector<float>& features) {
        // The m2cgen code outputs a double array of probabilities for each class
        double output[24];
        double input_arr[58];
        
        for(size_t i=0; i<features.size(); ++i) {
            input_arr[i] = features[i];
        }
        
        score(input_arr, output);
        
        // Find highest probability
        int max_idx = 0;
        for (int i = 1; i < 24; ++i) {
            if (output[i] > output[max_idx]) {
                max_idx = i;
            }
        }
        
        // Map index back to string
        std::vector<std::string> classes = {
            "A","B","C","D","E","F","G","H","I","K","L","M","N","O","P","Q","R","S","T","U","V","W","X","Y"
        };
        
        return classes[max_idx];
    }
};
